diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 60da48e1d95d..0e5bc9fd431f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -6127,6 +6127,109 @@ Instruction *InstCombinerImpl::foldICmpEquality(ICmpInst &I) {

   if (Instruction *ICmp = foldICmpIntrinsicWithIntrinsic(I, Builder))
     return ICmp;
+  // icmp eq X, (smin (smax X, lo), hi) --> (X - lo) u< (hi - lo + 1)
+  // icmp eq (smin (smax X, lo), hi), X --> same
+  // icmp eq X, (smax (smin X, hi), lo) --> same
+  // icmp eq (smax (smin X, hi), lo), X --> same
+  // Likewise for unsigned min/max.
+  {
+    Value *X;
+    const APInt *Lo, *Hi;
+    bool IsSigned;
+    auto MatchClamp = [&](Value *Op) -> bool {
+      // smin(smax(X, Lo), Hi)
+      if (match(Op, m_SMin(m_SMax(m_Value(X), m_APInt(Lo)), m_APInt(Hi))) ||
+          match(Op, m_SMin(m_SMax(m_APInt(Lo), m_Value(X)), m_APInt(Hi))) ||
+          match(Op, m_SMin(m_APInt(Hi), m_SMax(m_Value(X), m_APInt(Lo)))) ||
+          match(Op, m_SMin(m_APInt(Hi), m_SMax(m_APInt(Lo), m_Value(X))))) {
+        IsSigned = true;
+        return true;
+      }
+      // smax(smin(X, Hi), Lo)
+      if (match(Op, m_SMax(m_SMin(m_Value(X), m_APInt(Hi)), m_APInt(Lo))) ||
+          match(Op, m_SMax(m_SMin(m_APInt(Hi), m_Value(X)), m_APInt(Lo))) ||
+          match(Op, m_SMax(m_APInt(Lo), m_SMin(m_Value(X), m_APInt(Hi)))) ||
+          match(Op, m_SMax(m_APInt(Lo), m_SMin(m_APInt(Hi), m_Value(X))))) {
+        IsSigned = true;
+        return true;
+      }
+      // umin(umax(X, Lo), Hi)
+      if (match(Op, m_UMin(m_UMax(m_Value(X), m_APInt(Lo)), m_APInt(Hi))) ||
+          match(Op, m_UMin(m_UMax(m_APInt(Lo), m_Value(X)), m_APInt(Hi))) ||
+          match(Op, m_UMin(m_APInt(Hi), m_UMax(m_Value(X), m_APInt(Lo)))) ||
+          match(Op, m_UMin(m_APInt(Hi), m_UMax(m_APInt(Lo), m_Value(X))))) {
+        IsSigned = false;
+        return true;
+      }
+      // umax(umin(X, Hi), Lo)
+      if (match(Op, m_UMax(m_UMin(m_Value(X), m_APInt(Hi)), m_APInt(Lo))) ||
+          match(Op, m_UMax(m_UMin(m_APInt(Hi), m_Value(X)), m_APInt(Lo))) ||
+          match(Op, m_UMax(m_APInt(Lo), m_UMin(m_Value(X), m_APInt(Hi)))) ||
+          match(Op, m_UMax(m_APInt(Lo), m_UMin(m_APInt(Hi), m_Value(X))))) {
+        IsSigned = false;
+        return true;
+      }
+      return false;
+    };
+    // Helper to decompose X into A, B, C where X = A + B + C and C is constant.
+    // Returns true if decomposition succeeded (A and B are non-null, C is constant).
+    auto DecomposeAdd = [&](Value *X, Value *&A, Value *&B, APInt &C) -> bool {
+      C = APInt(X->getType()->getScalarSizeInBits(), 0);
+      // Match X = add (add A, C1), B  where C1 is constant.
+      const APInt *C1;
+      if (match(X, m_Add(m_Add(m_Value(A), m_APInt(C1)), m_Value(B))) ||
+          match(X, m_Add(m_Add(m_APInt(C1), m_Value(A)), m_Value(B)))) {
+        C = *C1;
+        return true;
+      }
+      // Match X = add B, (add A, C1)  (commuted)
+      if (match(X, m_Add(m_Value(B), m_Add(m_Value(A), m_APInt(C1)))) ||
+          match(X, m_Add(m_Value(B), m_Add(m_APInt(C1), m_Value(A))))) {
+        C = *C1;
+        return true;
+      }
+      // TODO: handle more patterns.
+      return false;
+    };
+    // Helper to build range check.
+    auto BuildRangeCheck = [&](const APInt &Lo, const APInt &Hi) -> Instruction* {
+      // Compute hi - lo + 1, but use unsigned arithmetic to avoid overflow.
+      APInt Diff = Hi - Lo + 1;
+      // Compute X - Lo, trying to fold constants.
+      APInt ConstOffset = -Lo;
+      Value *A, *B;
+      APInt C;
+      if (DecomposeAdd(X, A, B, C)) {
+        // Combine constants: C + ConstOffset
+        APInt NewC = C + ConstOffset;
+        // Build (A + NewC) + B, with constant on the right side.
+        Value *Sum = Builder.CreateAdd(A, ConstantInt::get(X->getType(), NewC));
+        Sum = Builder.CreateAdd(Sum, B);
+        ICmpInst::Predicate NewPred = Pred == ICmpInst::ICMP_EQ
+                                          ? ICmpInst::ICMP_ULT
+                                          : ICmpInst::ICMP_UGE;
+        return new ICmpInst(NewPred, Sum,
+                            ConstantInt::get(X->getType(), Diff));
+      }
+      // Generic fallback.
+      Value *NegLo = ConstantInt::get(X->getType(), -Lo);
+      Value *XSubLo = Builder.CreateAdd(X, NegLo);
+      ICmpInst::Predicate NewPred = Pred == ICmpInst::ICMP_EQ
+                                        ? ICmpInst::ICMP_ULT
+                                        : ICmpInst::ICMP_UGE;
+      return new ICmpInst(NewPred, XSubLo,
+                          ConstantInt::get(X->getType(), Diff));
+    };
+    // Try Op0 then Op1.
+    for (Value *Op : {Op0, Op1}) {
+      if (MatchClamp(Op)) {
+        // Check that Lo <= Hi according to signedness.
+        if ((IsSigned && Lo->sle(*Hi)) || (!IsSigned && Lo->ule(*Hi))) {
+          return BuildRangeCheck(*Lo, *Hi);
+        }
+      }
+    }
+  }

   // Match icmp eq (trunc (lshr A, BW), (ashr (trunc A), BW-1)), which checks
   // the top BW/2 + 1 bits are all the same. Create "A >=s INT_MIN && A <=s

